1	//! The `finalize` subcommand: squash + set-bookmark + push a jj
2	//! repo, optionally detached so trailing writes land first.
3	//!
4	//! Built for the bot to atomically finalize its `.claude` session
5	//! repo at end-of-step. Every action is opt-in (`--squash`,
6	//! `--push`, `--detach`, `--delay`). The detached path re-execs
7	//! `vc-x1 finalize --exec …` so its output and errors survive the
8	//! parent exiting; failures are dropped as markers under
9	//! `~/.cache/vc-x1/finalize-status` and surfaced on the next
10	//! `vc-x1` run.
11	
12	use std::path::{Path, PathBuf};
13	use std::process::Stdio;
14	use std::time::{SystemTime, UNIX_EPOCH};
15	
16	use clap::Args;
17	use log::{debug, info};
18	
19	use crate::common::run;
20	use crate::context::Context;
21	use crate::options_flags::squash::{SquashOption, SquashSpec};
22	use crate::subcommand::SubcommandRunner;
23	
24	/// Directory where the detached finalize child writes failure markers.
25	/// A subsequent `vc-x1` invocation scans this directory and surfaces
26	/// any failures to the user, closing the gap that the detached child's
27	/// non-zero exit isn't observable by the caller.
28	fn status_dir() -> Option<PathBuf> {
29	    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
30	}
31	
32	/// Drop a failure marker for the detached child whose non-zero exit
33	/// the caller can't observe.
34	fn write_failure_marker(params: &FinalizeParams, err: &str) {
35	    let Some(dir) = status_dir() else {
36	        return;
37	    };
38	    if std::fs::create_dir_all(&dir).is_err() {
39	        return;
40	    }
41	    let ns = SystemTime::now()
42	        .duration_since(UNIX_EPOCH)
43	        .map(|d| d.as_nanos())
44	        .unwrap_or(0); // OK: filesystem-sortable timestamp; 0 on the impossible pre-epoch path
45	    let pid = std::process::id();
46	    let path = dir.join(format!("{ns}-{pid}.status"));
47	    let content = format!(
48	        "timestamp_ns={ns}\npid={pid}\nrepo={}\nbookmark={}\nerror={err}\n",
49	        params.repo.display(),
50	        params.bookmark.as_deref().unwrap_or(""),
51	    );
52	    let _ = std::fs::write(&path, content);
53	}
54	
55	/// Read, print, and delete any failure markers left by previous detached
56	/// finalize children. Cheap no-op when the directory doesn't exist.
57	pub fn surface_previous_failures() {
58	    let Some(dir) = status_dir() else {
59	        return;
60	    };
61	    let Ok(entries) = std::fs::read_dir(&dir) else {
62	        return;
63	    };
64	    let mut paths: Vec<PathBuf> = entries
65	        .flatten()
66	        .map(|e| e.path())
67	        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
68	        .collect();
69	    paths.sort();
70	    for path in paths {
71	        if let Ok(content) = std::fs::read_to_string(&path) {
72	            eprintln!(
73	                "warn: previous finalize failure ({}):",
74	                path.file_stem()
75	                    .map(|s| s.to_string_lossy())
76	                    .unwrap_or_default() // OK: filename without extension; empty on unexpected absence
77	            );
78	            for line in content.lines() {
79	                eprintln!("  {line}");
80	            }
81	            let _ = std::fs::remove_file(&path);
82	        }
83	    }
84	}
