86	/// Squash, set bookmark, and/or push a jj repo.
87	///
88	/// Designed for the bot to atomically finalize its session repo:
89	/// --detach exits immediately, --delay waits for trailing writes,
90	/// --squash folds them in, --bookmark + --push sends it upstream.
91	/// Every flag is opt-in. See README.md for details.
92	#[derive(Args, Debug)]
93	pub struct FinalizeArgs {
94	    /// Path to jj repo
95	    #[arg(long, default_value = ".")]
96	    pub repo: PathBuf,
97	
98	    #[command(flatten)]
99	    pub squash: SquashOption,
100	
101	    /// Seconds to wait before squashing
102	    #[arg(long, default_value_t = 10.0)]
103	    pub delay: f64,
104	
105	    /// Existing bookmark to push to remote
106	    #[arg(long, value_name = "BOOKMARK")]
107	    pub push: Option<String>,
108	
109	    /// Detach and run in the background
110	    #[arg(long)]
111	    pub detach: bool,
112	
113	    /// The above `pub detach` is true when `--detach` is passed
114	    /// to the `finalize` subcommand. The app then `fork`s and
115	    /// spawns `vc-x1 finalize --exec …`, replacing `--detach`
116	    /// with `--exec`. The child sees `exec: true` and is routed
117	    /// through `finalize_exec()` to do the squash/push work in
118	    /// the background.
119	    ///
120	    /// Marked `hide = true` because it's an internal argument and
121	    /// should not appear in `-h` / `--help` output.
122	    #[arg(long, hide = true)]
123	    pub exec: bool,
124	}
125	
126	/// Per-invocation finalize inputs — the clap-free shape the
127	/// `finalize` op works against. Built from `FinalizeArgs` at the
128	/// binary edge via `TryFrom` (fallible only on repo-path
129	/// canonicalization — `--squash` is already parsed into a
130	/// `SquashSpec` by clap). The `--log` path lives on `Context`,
131	/// not here.
132	#[derive(Debug)]
133	pub struct FinalizeParams {
134	    pub repo: PathBuf,
135	    pub squash: Option<SquashSpec>,
136	    pub delay_secs: f64,
137	    pub bookmark: Option<String>,
138	    pub push: bool,
139	    pub detach: bool,
140	    pub exec: bool,
141	}
142	
143	impl TryFrom<&FinalizeArgs> for FinalizeParams {
144	    type Error = String;
145	
146	    /// Derive `push`/`bookmark` from `--push` and canonicalize
147	    /// `--repo` (so the detached child resolves it regardless of
148	    /// cwd); `--squash` was already parsed by clap.
149	    fn try_from(a: &FinalizeArgs) -> Result<Self, String> {
150	        let repo = std::fs::canonicalize(&a.repo)
151	            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
152	        Ok(FinalizeParams {
153	            repo,
154	            squash: a.squash.value.clone(),
155	            delay_secs: a.delay,
156	            bookmark: a.push.clone(),
157	            push: a.push.is_some(),
158	            detach: a.detach,
159	            exec: a.exec,
160	        })
161	    }
162	}
163	
164	impl SubcommandRunner for FinalizeArgs {
165	    type Params = FinalizeParams;
166	
167	    /// Delegate to the existing `TryFrom<&FinalizeArgs>` impl above.
168	    fn to_params(&self) -> Result<Self::Params, String> {
169	        FinalizeParams::try_from(self)
170	    }
171	
172	    /// Run the existing `finalize` op.
173	    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
174	        finalize(ctx, params)
175	    }
176	}
