178	/// Validate inputs synchronously before detaching.
179	///
180	/// Catches the common failure modes up front so the parent can exit
181	/// with a visible non-zero status — rather than discovering them in
182	/// the detached child where errors only reach the log file.
183	fn preflight(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
184	    debug!("preflight: checking params");
185	    let repo_str = params.repo.to_string_lossy();
186	    let cwd = std::path::Path::new(".");
187	
188	    // Verify squash revsets resolve to something.
189	    if let Some(ref sq) = params.squash {
190	        jj_rev_exists(&repo_str, cwd, &sq.source)
191	            .map_err(|e| format!("squash source '{}' does not resolve: {e}", sq.source))?;
192	        jj_rev_exists(&repo_str, cwd, &sq.target)
193	            .map_err(|e| format!("squash target '{}' does not resolve: {e}", sq.target))?;
194	    }
195	
196	    // Refuse to operate on a repo with conflicts.
197	    let conflicts = run(
198	        "jj",
199	        &[
200	            "log",
201	            "-r",
202	            "conflicts()",
203	            "--no-graph",
204	            "-T",
205	            "\"x\"",
206	            "-R",
207	            &repo_str,
208	        ],
209	        cwd,
210	    )?;
211	    if !conflicts.is_empty() {
212	        return Err(format!("repo '{repo_str}' has conflicts — resolve before finalize").into());
213	    }
214	
215	    // Bookmark: existence, tracking, forward-only move, push-target description.
216	    if let Some(ref bookmark) = params.bookmark {
217	        let exists = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
218	        if exists.is_empty() {
219	            return Err(format!("bookmark '{bookmark}' does not exist").into());
220	        }
221	
222	        crate::common::verify_tracking(&params.repo, bookmark)?;
223	
224	        let target_rev = params
225	            .squash
226	            .as_ref()
227	            .map(|sq| sq.target.as_str())
228	            .unwrap_or("@"); // OK: no squash spec → bookmark will point at current @
229	        let range = run(
230	            "jj",
231	            &[
232	                "log",
233	                "-r",
234	                &format!("{bookmark}::({target_rev})"),
235	                "--no-graph",
236	                "-T",
237	                "\"x\"",
238	                "-R",
239	                &repo_str,
240	            ],
241	            cwd,
242	        )?;
243	        if range.is_empty() {
244	            return Err(format!(
245	                "bookmark '{bookmark}' move is not forward — current position is not an \
246	                 ancestor of '{target_rev}' (would diverge)"
247	            )
248	            .into());
249	        }
250	
251	        if params.push {
252	            let desc = run(
253	                "jj",
254	                &[
255	                    "log",
256	                    "-r",
257	                    target_rev,
258	                    "--no-graph",
259	                    "-T",
260	                    "description",
261	                    "-R",
262	                    &repo_str,
263	                ],
264	                cwd,
265	            )?;
266	            if desc.trim().is_empty() {
267	                return Err(format!(
268	                    "push target '{target_rev}' has no description — push would fail \
269	                     (run `jj describe -r {target_rev} -R {repo_str}` first)"
270	                )
271	                .into());
272	            }
273	        }
274	    }
275	
276	    log_plan(params)?;
277	
278	    Ok(())
279	}
