281	/// Return Ok(()) if the revset resolves to one or more commits in `repo`.
282	fn jj_rev_exists(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<(), String> {
283	    run(
284	        "jj",
285	        &["log", "-r", rev, "--no-graph", "-T", "\"x\"", "-R", repo],
286	        cwd,
287	    )
288	    .map_err(|e| e.to_string())?;
289	    Ok(())
290	}
