292	/// Log what finalize is about to do so the user sees the plan before detach.
293	fn log_plan(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
294	    let repo_str = params.repo.to_string_lossy();
295	    let cwd = std::path::Path::new(".");
296	
297	    if let Some(ref sq) = params.squash {
298	        info!(
299	            "finalize: squash {} → {} in {}",
300	            sq.source, sq.target, repo_str
301	        );
302	    }
303	    if let Some(ref bookmark) = params.bookmark {
304	        let target_rev = params
305	            .squash
306	            .as_ref()
307	            .map(|sq| sq.target.as_str())
308	            .unwrap_or("@"); // OK: same as above
309	        let current = jj_rev_short(&repo_str, cwd, bookmark).unwrap_or_else(|_| "?".into()); // OK: logging only — fall back to "?" if revset fails
310	        let target = jj_rev_short(&repo_str, cwd, target_rev).unwrap_or_else(|_| "?".into()); // OK: same
311	        info!("finalize: set bookmark '{bookmark}' {current} → {target} ({target_rev})");
312	        if params.push {
313	            info!("finalize: push '{bookmark}' to remote");
314	        }
315	    }
316	
317	    Ok(())
318	}
