320	/// Short one-line summary of a revset: `<change_short> <commit_short>`.
321	fn jj_rev_short(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<String, String> {
322	    run(
323	        "jj",
324	        &[
325	            "log",
326	            "-r",
327	            rev,
328	            "--no-graph",
329	            "-T",
330	            "change_id.shortest(8) ++ \" \" ++ commit_id.shortest(8)",
331	            "-R",
332	            repo,
333	        ],
334	        cwd,
335	    )
336	    .map_err(|e| e.to_string())
337	}
