339	/// Do the squash / set-bookmark / push work — runs in the detached
340	/// child when `--detach`, inline otherwise.
341	fn finalize_exec(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
342	    debug!("finalize_exec: starting params={params:?}");
343	    let repo_str = params.repo.to_string_lossy();
344	    let cwd = std::path::Path::new(".");
345	
346	    // Squash if requested
347	    if let Some(ref sq) = params.squash {
348	        let delay = std::time::Duration::from_secs_f64(params.delay_secs);
349	        debug!("finalize_exec: sleeping {delay:?}");
350	        std::thread::sleep(delay);
351	
352	        info!("finalize: squashing {} → {}...", sq.source, sq.target);
353	        run(
354	            "jj",
355	            &[
356	                "squash",
357	                "--ignore-immutable",
358	                "--use-destination-message",
359	                "--from",
360	                &sq.source,
361	                "--into",
362	                &sq.target,
363	                "-R",
364	                &repo_str,
365	            ],
366	            cwd,
367	        )?;
368	    }
369	
370	    // Set bookmark and push if requested
371	    if let Some(ref bookmark) = params.bookmark {
372	        // Verify bookmark exists — don't silently create new ones
373	        let result = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
374	        if result.is_empty() {
375	            return Err(format!("bookmark '{bookmark}' does not exist").into());
376	        }
377	
378	        let rev = params
379	            .squash
380	            .as_ref()
381	            .map(|sq| sq.target.as_str())
382	            .unwrap_or("@"); // OK: no squash spec → bookmark points at current @
383	        info!("finalize: setting bookmark '{bookmark}' to {rev}...");
384	        run(
385	            "jj",
386	            &["bookmark", "set", bookmark, "-r", rev, "-R", &repo_str],
387	            cwd,
388	        )?;
389	
390	        if params.push {
391	            info!("finalize: pushing '{bookmark}' to origin...");
392	            run(
393	                "jj",
394	                &["git", "push", "--bookmark", bookmark, "-R", &repo_str],
395	                &params.repo,
396	            )?;
397	        }
398	    }
399	
400	    info!("finalize: done");
401	    debug!("finalize_exec: done");
402	    Ok(())
403	}
