405	/// Build the argv for the detached re-exec: `finalize --exec …`,
406	/// mirroring `params` plus the `--log` path so the child logs to
407	/// the same file.
408	pub fn build_exec_args(params: &FinalizeParams, log: Option<&Path>) -> Vec<String> {
409	    let mut args = vec![
410	        "finalize".to_string(),
411	        "--exec".to_string(),
412	        "--repo".to_string(),
413	        params.repo.to_string_lossy().to_string(),
414	    ];
415	    if let Some(ref sq) = params.squash {
416	        args.push("--squash".to_string());
417	        args.push(format!("{},{}", sq.source, sq.target));
418	        args.push("--delay".to_string());
419	        args.push(params.delay_secs.to_string());
420	    }
421	    if let Some(ref bookmark) = params.bookmark {
422	        args.push("--push".to_string());
423	        args.push(bookmark.clone());
424	    }
425	    if let Some(log) = log {
426	        args.push("--log".to_string());
427	        args.push(log.to_string_lossy().to_string());
428	    }
429	    args
430	}
