432	/// Spawn a detached child process with `--exec` and return immediately.
433	/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
434	/// it to `finalize_exec()` where the actual work happens.
435	fn detach(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
436	    debug!("detach: parent starting params={params:?}");
437	
438	    let exe = std::env::current_exe()?;
439	    let args = build_exec_args(params, ctx.log.as_deref());
440	    debug!("detach: exe={exe:?} args={args:?}");
441	
442	    let mut cmd = std::process::Command::new(exe);
443	    cmd.args(&args).stdin(Stdio::null());
444	
445	    // Hand the child the user's controlling terminal when one exists so
446	    // its output stays visible after the parent exits. Inherited pipes
447	    // are unreliable here — the bash-tool / cron caller typically closes
448	    // its read end on parent exit, silently dropping child writes. Fall
449	    // back to null when there is no tty (pipe-invoked / CI / Windows);
450	    // the log file is authoritative in that case.
451	    match std::fs::OpenOptions::new()
452	        .read(true)
453	        .write(true)
454	        .open("/dev/tty")
455	    {
456	        Ok(tty) => {
457	            debug!("detach: /dev/tty opened, child output → terminal");
458	            let out = tty.try_clone()?;
459	            cmd.stdout(Stdio::from(out));
460	            cmd.stderr(Stdio::from(tty));
461	        }
462	        Err(e) => {
463	            debug!("detach: /dev/tty unavailable ({e}), child output → null");
464	            cmd.stdout(Stdio::null());
465	            cmd.stderr(Stdio::null());
466	        }
467	    }
468	
469	    #[cfg(unix)]
470	    {
471	        use std::os::unix::process::CommandExt;
472	        unsafe {
473	            cmd.pre_exec(|| {
474	                libc::setsid();
475	                Ok(())
476	            });
477	        }
478	    }
479	
480	    let child = cmd.spawn()?;
481	    debug!("detach: spawned child pid={}", child.id());
482	    match &ctx.log {
483	        Some(log) => info!(
484	            "finalize: detached (pid {}), log: {}",
485	            child.id(),
486	            log.display()
487	        ),
488	        None => info!("finalize: detached (pid {})", child.id()),
489	    }
490	    Ok(())
491	}
