493	/// Run the `finalize` subcommand: preflight, then either detach a
494	/// child to do the work or do it inline.
495	pub fn finalize(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
496	    // Nothing to do — show help hint
497	    if params.squash.is_none() && !params.push {
498	        return Err("nothing to do (see --help for options)".into());
499	    }
500	
501	    debug!("finalize: entry params={params:?}");
502	
503	    // Validate synchronously before detaching so failures exit with a
504	    // visible non-zero status rather than hiding in the detached child's log.
505	    // Skip in --exec (the re-entered child already passed preflight in the parent).
506	    if !params.exec {
507	        preflight(params)?;
508	    }
509	
510	    let result = if params.detach && !params.exec {
511	        detach(ctx, params)
512	    } else {
513	        finalize_exec(params)
514	    };
515	    match &result {
516	        Ok(()) => debug!("finalize: exit ok"),
517	        Err(e) => {
518	            debug!("finalize: exit err={e}");
519	            // In the detached-child path the caller can't observe our
520	            // non-zero exit. Drop a failure marker so a later vc-x1
521	            // invocation can surface the problem.
522	            if params.exec {
523	                write_failure_marker(params, &e.to_string());
524	            }
525	        }
526	    }
527	    result
528	}
